#!/usr/bin/env node

/**
 * Uploads the API endpoint coverage summary to Better Testing.
 *
 * Requires:
 *   FLAKEY_API_KEY  — API key
 *   FLAKEY_RUN_ID   — run ID returned by the backend after test:smoke upload
 *
 * Optional:
 *   FLAKEY_API_URL  — defaults to http://localhost:3000
 *
 * The file coverage/coverage-summary.json must already exist (generated by
 * node scripts/generate-coverage.js which runs as part of test:smoke).
 */

import { spawnSync } from "child_process";
import { readFileSync, existsSync } from "fs";

// Load .env
if (existsSync(".env")) {
  for (const line of readFileSync(".env", "utf-8").split("\n")) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    const [key, ...rest] = trimmed.split("=");
    if (key && !process.env[key]) process.env[key] = rest.join("=");
  }
}

const apiKey = process.env.FLAKEY_API_KEY ?? "";
const apiUrl = process.env.FLAKEY_API_URL ?? "http://localhost:3000";
const runId = process.env.FLAKEY_RUN_ID ?? "";
const coverageFile = "coverage/coverage-summary.json";

if (!apiKey) {
  console.error("  [flakey] No FLAKEY_API_KEY set. Create a .env file or export the variable.");
  process.exit(1);
}

if (!runId) {
  console.warn(
    "  [flakey] FLAKEY_RUN_ID is not set — skipping coverage upload.\n" +
    "  Set FLAKEY_RUN_ID to the run ID returned after test:smoke to link coverage to that run."
  );
  process.exit(0);
}

if (!existsSync(coverageFile)) {
  console.error(`  [flakey] Coverage file not found at ${coverageFile}.`);
  console.error("  Run: node scripts/generate-coverage.js  (or pnpm test:smoke which runs it automatically)");
  process.exit(1);
}

const result = spawnSync("npx", [
  "tsx", "../../packages/flakey-cli/src/index.ts",
  "coverage",
  "--run-id", runId,
  "--file", coverageFile,
  "--api-key", apiKey,
], {
  stdio: "inherit",
  env: { ...process.env, FLAKEY_API_URL: apiUrl },
});

process.exit(result.status ?? 1);
